<body>

    <!-- Desktop Environment -->
    <div id="desktop">

        <!-- Files Window -->
        <div id="files-window" class="window hidden">
            <div class="title-bar">
                <span class="window-title">Files</span>
                <button class="win-close">&times;</button>
            </div>
            <div id="files-toolbar">
                <button id="files-up" class="btn-up" title="Go Up">↑</button>
                <span id="files-path">/</span>
            </div>
            <div id="files-list"></div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window hidden">
            <div class="title-bar">
                <span class="window-title">Text Editor</span>
                <button class="win-close">&times;</button>
            </div>
            <div id="tabs-container">
                <!-- Tabs injected here -->
            </div>
            <div id="editor-container">
                <textarea id="editor" placeholder="Type here..."></textarea>
            </div>
        </div>

    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <div class="launcher icon-files" id="open-files" title="Files">
            📁
        </div>
        <div class="launcher icon-notepad" id="open-notepad" title="Notepad">
            📝
        </div>
    </div>

    <script>
        // --- State Management ---

        // Fake File System Structure
        const fileSystem = {
            name: '',
            type: 'dir',
            children: {
                bin: { name: 'bin', type: 'dir', children: {} },
                etc: { name: 'etc', type: 'dir', children: {} },
                home: { 
                    name: 'home', 
                    type: 'dir', 
                    children: {
                        user: {
                            name: 'user',
                            type: 'dir',
                            children: {
                                Documents: { name: 'Documents', type: 'dir', children: {} },
                                Downloads: { name: 'Downloads', type: 'dir', children: {} },
                                Pictures: { name: 'Pictures', type: 'dir', children: {} }
                            }
                        }
                    }
                },
                usr: { name: 'usr', type: 'dir', children: {} },
                var: { name: 'var', type: 'dir', children: {} }
            }
        };

        // Notepad State (Persisted in localStorage)
        let notepadData = JSON.parse(localStorage.getItem('notepad_data')) || {};

        // Current File System Path Stack
        let pathStack = []; 
        let currentPathStr = '/';

        // --- DOM Elements ---
        const filesWindow = document.getElementById('files-window');
        const notepadWindow = document.getElementById('notepad-window');
        const openFilesBtn = document.getElementById('open-files');
        const openNotepadBtn = document.getElementById('open-notepad');

        const filesPathEl = document.getElementById('files-path');
        const filesListEl = document.getElementById('files-list');
        const filesUpBtn = document.getElementById('files-up');

        const tabsContainer = document.getElementById('tabs-container');
        const editor = document.getElementById('editor');
        const newTabBtn = document.createElement('button');
        newTabBtn.id = 'new-tab';
        newTabBtn.innerHTML = '+';
        newTabBtn.className = ''; // No class initially, will add style inline or via JS

        const closeButtons = document.querySelectorAll('.win-close');

        // --- Initialization ---

        function init() {
            // Setup Notepad persistence
            if (Object.keys(notepadData).length === 0) {
                // Create one default tab on first load
                createTab('Untitled-1', '');
            }

            // Render initial tabs
            renderTabs();

            // Bind events
            bindEvents();
        }

        function bindEvents() {
            // Launchers
            openFilesBtn.addEventListener('click', () => {
                filesWindow.classList.remove('hidden');
                resetFileView();
            });

            openNotepadBtn.addEventListener('click', () => {
                notepadWindow.classList.remove('hidden');
                renderTabs(); // Refresh tabs to show active state
            });

            // Window Close Buttons
            closeButtons.forEach(btn => {
                btn.addEventListener('click', (e) => {
                    const win = e.currentTarget.closest('.window');
                    win.classList.add('hidden');
                });
            });

            // Files App Events
            filesUpBtn.addEventListener('click', () => navigateUp());

            // Notepad Events
            newTabBtn.addEventListener('click', createNewTab);

            editor.addEventListener('input', saveNotepadState);
        }

        // --- File System Logic ---

        function resetFileView() {
            pathStack = [];
            currentPathStr = '/';
            renderFiles();
        }

        function navigateUp() {
            if (pathStack.length > 0) {
                pathStack.pop();
                updatePathDisplay();
                renderFiles();
            }
        }

        function getChildren(pathObj) {
            return Object.keys(pathObj.children).map(key => ({
                name: key,
                type: 'dir',
                children: pathObj.children[key]
            }));
        }

        function navigateInto(name, parentObj) {
            const child = parentObj.children[name];
            if (child && child.type === 'dir') {
                // Add to stack
                pathStack.push({ name: child.name, children: child.children });

                // Update display path string
                let newPath = '/';
                let currentDir = fileSystem;
                for(let p of pathStack) {
                    newPath += `/${p.name}`;
                    currentDir = p.children[p.name];
                }
                currentPathStr = newPath;

                updatePathDisplay();
                renderFiles();
            }
        }

        function updatePathDisplay() {
            filesPathEl.textContent = currentPathStr;
        }

        function renderFiles() {
            filesListEl.innerHTML = '';

            if (pathStack.length === 0) {
                // Root level
                const rootChildren = Object.keys(fileSystem.children).map(key => ({
                    name: key,
                    type: 'dir',
                    children: fileSystem.children[key]
                }));
                renderList(rootChildren);
            } else {
                // Deep level
                const currentDirObj = pathStack[pathStack.length - 1];
                const children = Object.keys(currentDirObj.children).map(key => ({
                    name: key,
                    type: 'dir',
                    children: currentDirObj.children[key]
                }));
                renderList(children);
            }
        }

        function renderList(items) {
            items.forEach(item => {
                const el = document.createElement('div');
                el.className = `fs-item ${item.type}`;
                el.textContent = item.name;

                // Double click to enter
                el.addEventListener('dblclick', () => navigateInto(item.name, pathStack[pathStack.length-1]));

                filesListEl.appendChild(el);
            });
        }

        function resetFileView() {
             pathStack = [];
             currentPathStr = '/';
             renderFiles();
        }

        // --- Notepad Logic ---

        function saveNotepadState() {
            const activeTabId = document.querySelector('.tab.active').id;
            notepadData[activeTabId] = editor.value;
            localStorage.setItem('notepad_data', JSON.stringify(notepadData));
        }

        function createNewTab() {
            const timestamp = Date.now();
            const newId = `tab-${timestamp}`;
            const title = `Untitled-${Math.floor(Math.random() * 100)}`;

            // Create data entry if not exists
            if (!notepadData[newId]) {
                notepadData[newId] = '';
            }

            createTab(title, newId);
        }

        function createTab(title, id) {
            const tabEl = document.createElement('div');
            tabEl.className = 'tab';
            tabEl.id = id;
            tabEl.textContent = title;

            // Click to switch
            tabEl.addEventListener('click', () => switchTab(id));

            tabsContainer.appendChild(tabEl);

            // If this is the first tab (or only one), make it active immediately
            if (tabsContainer.children.length === 1) {
                switchTab(id);
            } else {
                // Update active class on existing tabs to remove old highlights
                document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
                tabEl.classList.add('active');

                // Focus editor and load content
                editor.value = notepadData[id] || '';
                saveNotepadState();
            }
        }

        function switchTab(id) {
            document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
            const activeTab = document.getElementById(id);

            if (activeTab) {
                activeTab.classList.add('active');
                editor.value = notepadData[id];
                saveNotepadState();
            }
        }

        function renderTabs() {
            // Re-render tabs to ensure state matches DOM
            tabsContainer.innerHTML = '';

            Object.keys(notepadData).forEach(id => {
                const title = document.getElementById(id).textContent;
                createTab(title, id);
            });
        }

        // --- Start App ---
        init();

    </script>
</body>
</html>
